import (
    "context"
    "fmt"

    "github.com/samber/lo"
    "github.com/openmeterio/openmeter/openmeter/customer"
    "github.com/openmeterio/openmeter/openmeter/entitlement"
    "github.com/openmeterio/openmeter/pkg/clock"
    "github.com/openmeterio/openmeter/pkg/models"
)

func (v *Validator) ValidateUpdateCustomer(ctx context.Context, input customer.UpdateCustomerInput) error {
    if err := input.Validate(); err != nil {
        return err
    }
    now := clock.Now()
    entitlements, err := v.entitlementRepo.ListEntitlements(ctx, entitlement.ListEntitlementsParams{
        CustomerIDs: []string{input.ID},
        Namespaces:  []string{input.Namespace},
        ActiveAt:    lo.ToPtr(now),
    })
    if err != nil {
        return fmt.Errorf("failed to list customer entitlements: %w", err)
    }
    if len(entitlements.Items) > 0 {
        return models.NewGenericConflictError(fmt.Errorf("customer %s has active entitlements", input.ID))
    }
    return nil
}
